import vex

@vex.checkpoint(
    name="crew_delegation_limit",
    spec={
        "max_delegations": 3,
        "blocked_patterns": ["redelegate", "ask.*again"]
    }
)
def check_delegation_loop(task_output: str, context: dict) -> bool:
    delegation_count = context.get('delegation_count', 0)
    if delegation_count > 3:
        return False
    return "loop" not in task_output.lower()

# Apply to agent tasks
intent_task.checkpoint = check_delegation_loop
retrieval_task.checkpoint = check_delegation_loop

@vex.checkpoint(
    name="conversation_coherence",
    spec={"semantic_drift_threshold": 0.3}
)
def check_coherence(response: str, conversation_history: list) -> bool:
    if not conversation_history:
        return True

    # Check semantic similarity to conversation thread
    thread_embedding = vex.embed(" ".join([msg['user'] + msg['bot'] for msg in conversation_history[-3:]]))
    response_embedding = vex.embed(response)

    similarity = vex.cosine_similarity(thread_embedding, response_embedding)

    # Verify response addresses last user intent
    return similarity > 0.7

response_task.checkpoint = lambda output, ctx: check_coherence(output, ctx.get('memory', []))
